//! Data model for parsed ontology entity definitions.
//!
//! These types represent the metadata extracted from `#[ontology(...)]` annotations
//! on schema structs. They drive all code generation.

/// A parsed entity definition, extracted from a schema struct annotated with
/// `#[ontology(entity, ...)]`.
#[derive(Debug, Clone)]
pub struct EntityDef {
    /// Rust struct name (e.g., `Node`, `Contract`).
    pub name: String,

    /// Subdirectory for markdown files (e.g., `"nodes"`).
    /// Defaults to snake_case of `name` if not specified.
    pub directory: String,

    /// SeaORM table name (e.g., `"nodes"`).
    /// Defaults to snake_case of `name` if not specified.
    pub table: String,

    /// The `type:` value in frontmatter YAML (e.g., `"node"`).
    /// Defaults to snake_case of `name` if not specified.
    pub type_name: String,

    /// ID prefix for global uniqueness (e.g., `"node"`, `"req"`).
    /// Defaults to snake_case of `name` if not specified.
    pub prefix: String,

    /// All fields on the struct.
    pub fields: Vec<FieldDef>,
}

/// A parsed field definition.
#[derive(Debug, Clone)]
pub struct FieldDef {
    /// Rust field name (e.g., `parent_id`, `contains`).
    pub name: String,

    /// The Rust type of the field.
    pub field_type: FieldType,

    /// Role of this field in the ontology model.
    pub role: FieldRole,

    /// If true, the field has `#[serde(default)]`.
    pub serde_default: bool,

    /// If true, render Vec fields as YAML block sequences (one item per line)
    /// instead of inline `[a, b, c]`.
    pub multiline_list: bool,

    /// If set, only render this field when the value differs from the default.
    /// E.g., `default_value = "active"` means skip rendering when value == "active".
    pub default_value: Option<String>,
}

/// Simplified representation of a Rust field type, capturing only what codegen
/// needs to know.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum FieldType {
    /// `String`
    String,
    /// `Option<String>`
    OptionString,
    /// `Option<T>` where T is an enum type (stored as string in DB).
    OptionEnum(String),
    /// `Vec<String>`
    VecString,
    /// `Vec<T>` where T is a structured type (e.g., `AcceptanceCriterion`).
    VecStruct(String),
    /// `i32`
    I32,
    /// `Option<i32>`
    OptionI32,
    /// `i64` (also used for `u64` — SQLite has no unsigned integers)
    I64,
    /// `Option<i64>` (also used for `Option<u64>`)
    OptionI64,
    /// `f32`
    F32,
    /// `Option<f32>`
    OptionF32,
    /// `f64`
    F64,
    /// `Option<f64>`
    OptionF64,
    /// `bool`
    Bool,
    /// `Option<bool>`
    OptionBool,
    /// Any other type we don't specifically handle.
    Other(String),
}

/// The role of a field in the ontology model, derived from `#[ontology(...)]` attributes.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum FieldRole {
    /// `#[ontology(id)]` — primary key field.
    Id,

    /// `#[ontology(body)]` — markdown body, not part of frontmatter.
    Body,

    /// `#[ontology(enum_field)]` — enum stored as string in DB.
    EnumField,

    /// `#[ontology(relation(...))]` — a cross-reference to another entity.
    Relation(RelationInfo),

    /// No ontology annotation — a plain data field.
    /// For `Vec<String>` fields, stored as JSON in DB.
    Plain,

    /// `#[ontology(skip)]` — excluded from codegen.
    Skip,
}

/// Metadata about a relation field, extracted from `#[ontology(relation(...))]`.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RelationInfo {
    /// The kind of relation.
    pub kind: RelationKind,

    /// The target entity name (e.g., `"Node"`, `"Requirement"`).
    pub target: String,

    /// Override for the junction table name (many_to_many only). Derived if not specified.
    pub junction: Option<String>,

    /// The FK column on the target entity that points back to this entity (has_many only).
    pub foreign_key: Option<String>,
}

/// The cardinality/kind of a relation.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum RelationKind {
    /// Many-to-one: this entity has a FK column pointing to the target.
    /// Expressed as `Option<String>` or `String` in the schema.
    BelongsTo,

    /// One-to-many reverse: the target entity has a FK column pointing back to this entity.
    /// No junction table needed. Expressed as `Vec<String>` in the schema.
    /// Requires `foreign_key` in `RelationInfo` to identify the FK column on the target.
    HasMany,

    /// Many-to-many: requires a junction table.
    /// Expressed as `Vec<String>` in the schema.
    ManyToMany,
}

impl FieldDef {
    /// Create a new FieldDef with the given name, type, and role.
    /// Rendering hints default to off.
    pub fn new(name: impl Into<String>, field_type: FieldType, role: FieldRole) -> Self {
        Self { name: name.into(), field_type, role, serde_default: false, multiline_list: false, default_value: None }
    }
}

impl EntityDef {
    /// Get the field marked as `#[ontology(id)]`, if any.
    pub fn id_field(&self) -> Option<&FieldDef> {
        self.fields.iter().find(|f| f.role == FieldRole::Id)
    }

    /// Get the field marked as `#[ontology(body)]`, if any.
    pub fn body_field(&self) -> Option<&FieldDef> {
        self.fields.iter().find(|f| f.role == FieldRole::Body)
    }

    /// Get all relation fields.
    pub fn relation_fields(&self) -> impl Iterator<Item = &FieldDef> {
        self.fields.iter().filter(|f| matches!(f.role, FieldRole::Relation(_)))
    }

    /// Get all many-to-many relation fields (those needing junction tables).
    pub fn junction_relations(&self) -> impl Iterator<Item = (&FieldDef, &RelationInfo)> {
        self.fields.iter().filter_map(|f| match &f.role {
            FieldRole::Relation(info) if info.kind == RelationKind::ManyToMany => Some((f, info)),
            _ => None,
        })
    }

    /// Get all has-many relation fields (reverse of belongs_to, no junction table).
    pub fn has_many_relations(&self) -> impl Iterator<Item = (&FieldDef, &RelationInfo)> {
        self.fields.iter().filter_map(|f| match &f.role {
            FieldRole::Relation(info) if info.kind == RelationKind::HasMany => Some((f, info)),
            _ => None,
        })
    }

    /// Get all belongs-to relation fields (FK columns).
    pub fn belongs_to_relations(&self) -> impl Iterator<Item = (&FieldDef, &RelationInfo)> {
        self.fields.iter().filter_map(|f| match &f.role {
            FieldRole::Relation(info) if info.kind == RelationKind::BelongsTo => Some((f, info)),
            _ => None,
        })
    }
}
